import React, { useState, useEffect } from 'react';
import {
  View,
  Text,
  TouchableOpacity,
  TextInput,
  StyleSheet,
  Alert,
  ActivityIndicator,
} from 'react-native';
import ReactNativeBiometrics from 'react-native-biometrics';
import AsyncStorage from '@react-native-async-storage/async-storage';

const rnBiometrics = new ReactNativeBiometrics();

const AUTH_KEY = '@authenticated';
const PASSWORD_KEY = '@user_password';

const BiometricAuth = ({ onAuthSuccess }) => {
  const [biometricsAvailable, setBiometricsAvailable] = useState(false);
  const [biometryType, setBiometryType] = useState(null);
  const [loading, setLoading] = useState(true);
  const [showPasswordFallback, setShowPasswordFallback] = useState(false);
  const [password, setPassword] = useState('');
  const [savedPassword, setSavedPassword] = useState('');

  useEffect(() => {
    checkBiometrics();
    checkAuthStatus();
    loadSavedPassword();
  }, []);

  const checkBiometrics = async () => {
    try {
      const { available, biometryType } = await rnBiometrics.isSensorAvailable();
      setBiometricsAvailable(available);
      setBiometryType(biometryType);
    } catch (error) {
      console.error('Error checking biometrics:', error);
      setBiometricsAvailable(false);
    }
  };

  const checkAuthStatus = async () => {
    try {
      const authStatus = await AsyncStorage.getItem(AUTH_KEY);
      if (authStatus === 'true') {
        onAuthSuccess();
      }
    } catch (error) {
      console.error('Error checking auth status:', error);
    } finally {
      setLoading(false);
    }
  };

  const loadSavedPassword = async () => {
    try {
      const saved = await AsyncStorage.getItem(PASSWORD_KEY);
      if (saved) {
        setSavedPassword(saved);
      }
    } catch (error) {
      console.error('Error loading password:', error);
    }
  };

  const handleBiometricAuth = async () => {
    try {
      const { success } = await rnBiometrics.simplePrompt({
        promptMessage: 'Authenticate to continue',
        cancelButtonText: 'Cancel',
      });

      if (success) {
        await AsyncStorage.setItem(AUTH_KEY, 'true');
        onAuthSuccess();
      } else {
        Alert.alert('Authentication Failed', 'Biometric authentication was not successful');
      }
    } catch (error) {
      console.error('Biometric auth error:', error);
      Alert.alert('Error', 'An error occurred during biometric authentication');
    }
  };

  const handlePasswordAuth = async () => {
    if (!password) {
      Alert.alert('Error', 'Please enter a password');
      return;
    }

    if (savedPassword) {
      if (password === savedPassword) {
        await AsyncStorage.setItem(AUTH_KEY, 'true');
        onAuthSuccess();
      } else {
        Alert.alert('Error', 'Incorrect password');
      }
    } else {
      await AsyncStorage.setItem(PASSWORD_KEY, password);
      await AsyncStorage.setItem(AUTH_KEY, 'true');
      onAuthSuccess();
    }
  };

  const getBiometryTypeName = () => {
    switch (biometryType) {
      case 'FaceID':
        return 'Face ID';
      case 'TouchID':
        return 'Touch ID';
      case 'Biometrics':
        return 'Biometric';
      default:
        return 'Biometric';
    }
  };

  if (loading) {
    return (
      <View style={styles.container}>
        <ActivityIndicator size="large" color="#007AFF" />
      </View>
    );
  }

  return (
    <View style={styles.container}>
      <Text style={styles.title}>Authentication Required</Text>

      {biometricsAvailable && !showPasswordFallback ? (
        <View style={styles.biometricContainer}>
          <Text style={styles.subtitle}>
            Use {getBiometryTypeName()} to authenticate
          </Text>
          <TouchableOpacity style={styles.button} onPress={handleBiometricAuth}>
            <Text style={styles.buttonText}>Authenticate with {getBiometryTypeName()}</Text>
          </TouchableOpacity>
          <TouchableOpacity
            style={styles.linkButton}
            onPress={() => setShowPasswordFallback(true)}
          >
            <Text style={styles.linkText}>Use Password Instead</Text>
          </TouchableOpacity>
        </View>
      ) : (
        <View style={styles.passwordContainer}>
          <Text style={styles.subtitle}>
            {savedPassword ? 'Enter your password' : 'Set a password'}
          </Text>
          <TextInput
            style={styles.input}
            placeholder="Password"
            secureTextEntry
            value={password}
            onChangeText={setPassword}
            autoCapitalize="none"
          />
          <TouchableOpacity style={styles.button} onPress={handlePasswordAuth}>
            <Text style={styles.buttonText}>
              {savedPassword ? 'Login' : 'Set Password'}
            </Text>
          </TouchableOpacity>
          {biometricsAvailable && (
            <TouchableOpacity
              style={styles.linkButton}
              onPress={() => setShowPasswordFallback(false)}
            >
              <Text style={styles.linkText}>Use {getBiometryTypeName()} Instead</Text>
            </TouchableOpacity>
          )}
        </View>
      )}
    </View>
  );
};

const App = () => {
  const [isAuthenticated, setIsAuthenticated] = useState(false);

  const handleAuthSuccess = () => {
    setIsAuthenticated(true);
  };

  const handleLogout = async () => {
    try {
      await AsyncStorage.removeItem(AUTH_KEY);
      setIsAuthenticated(false);
    } catch (error) {
      console.error('Error logging out:', error);
    }
  };

  if (!isAuthenticated) {
    return <BiometricAuth onAuthSuccess={handleAuthSuccess} />;
  }

  return (
    <View style={styles.container}>
      <Text style={styles.title}>Welcome!</Text>
      <Text style={styles.subtitle}>You are successfully authenticated</Text>
      <TouchableOpacity style={styles.button} onPress={handleLogout}>
        <Text style={styles.buttonText}>Logout</Text>
      </TouchableOpacity>
    </View>
  );
};

